previewCss:
.darma-loader-darma-custom-458 {color: var(--loader-color, #e11d48);
  --loader-secondary-color: var(--loader-secondary-color, #fb7185);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 75px;
   aspect-ratio: 1;
   display: grid;
}
.darma-loader-darma-custom-458:before, .darma-loader-darma-custom-458:after  {
  content: "";
   grid-area: 1/1;
   width: 35px;
   aspect-ratio: 1;
   box-shadow: 0 0 0 3px currentColor inset;
   filter: drop-shadow(40px 40px 0 currentColor);
   animation: darma-loader-darma-custom-458-l8 2s infinite alternate;
}
.darma-loader-darma-custom-458:after  {
  margin: 0 0 0 auto;
   filter: drop-shadow(-40px 40px 0 currentColor);
   animation-delay: -1s;
}
@keyframes darma-loader-darma-custom-458-l8  {
  0%,10% {border-radius:0}
30%,40% {border-radius:50% 0}
60%,70% {border-radius:50%}
90%,100% {border-radius:0 50%}
}

